108	    stepNum++;
109	  }
110	
111	  const menuStep = stepNum;
112	  const haltStep = stepNum + 1;
113	  const inputStep = stepNum + 2;
114	  const executeStep = stepNum + 3;
115	
116	  let xml = `  <activation critical="MANDATORY">
117	    <step n="1">Load persona from this current agent file (already in context)</step>
118	    <step n="2">IMMEDIATE ACTION REQUIRED - BEFORE ANY OUTPUT:
119	        - Load and read {project-root}/${skfFolder}/config.yaml NOW
120	        - Store ALL fields as session variables: {user_name}, {communication_language}, {skills_output_folder}, {forge_data_folder}, {project_name}
121	        - VERIFY: If config not loaded, STOP and report error to user
122	        - DO NOT PROCEED to step 3 until config is successfully loaded and variables stored
123	    </step>
124	    <step n="3">Remember: user's name is {user_name}</step>
125	${agentSteps}    <step n="${menuStep}">Show greeting using {user_name} from config, communicate in {communication_language}, then display numbered list of ALL menu items from menu section</step>
126	    <step n="${haltStep}">STOP and WAIT for user input - do NOT execute menu items automatically - accept number or cmd trigger or fuzzy command match</step>
127	    <step n="${inputStep}">On user input: Number -> execute menu item[n] | Text -> case-insensitive substring match | Multiple matches -> ask user to clarify | No match -> show "Not recognized"</step>
128	    <step n="${executeStep}">When executing a menu item: Check menu-handlers section below - extract any attributes from the selected menu item (workflow, exec, data, action) and follow the corresponding handler instructions</step>
